// ============================================================
// pages/ApplicationDetails.jsx — Admin: Single Application View
// ============================================================
// Admin can:
//  - View full merchant profile + documents
//  - Download uploaded documents
//  - Update status: pending / under_review / approved / rejected
//  - Add remarks/comments
// ============================================================

import React, { useEffect, useState } from "react";
import { useParams, Link } from "react-router-dom";
import { adminAPI } from "../services/api";
import { useAuth } from "../context/AuthContext";
import "../styles/dashboard.css";

const STATUS_OPTIONS = [
  { value: "pending",      label: "Pending" },
  { value: "under_review", label: "Under Review" },
  { value: "approved",     label: "Approved" },
  { value: "rejected",     label: "Rejected" },
];

function ApplicationDetails() {
  const { id }     = useParams();  // Get application ID from URL: /admin/applications/:id
  const { logout } = useAuth();

  const [application, setApplication] = useState(null);
  const [loading, setLoading]         = useState(true);

  // Admin action state
  const [newStatus,  setNewStatus]  = useState("");
  const [remarks,    setRemarks]    = useState("");
  const [updating,   setUpdating]   = useState(false);
  const [updateMsg,  setUpdateMsg]  = useState("");
  const apiBase = (process.env.REACT_APP_API_URL || "http://localhost:8000/api").replace(/\/api\/?$/, "");

  // Load application details on mount
  useEffect(() => {
    adminAPI.getApplication(id)
      .then((res) => {
        setApplication(res.data);
        setNewStatus(res.data.status);     // Pre-fill current status
        setRemarks(res.data.remarks || ""); // Pre-fill existing remarks
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, [id]);

  // Submit status update
  const handleUpdateStatus = async () => {
    setUpdating(true);
    setUpdateMsg("");
    try {
      const res = await adminAPI.updateStatus(id, newStatus, remarks);
      setApplication(res.data);
      setUpdateMsg("Status updated successfully!");
    } catch (err) {
      setUpdateMsg("Failed to update status.");
    } finally {
      setUpdating(false);
    }
  };

  const m = application?.merchant;

  return (
    <div className="dashboard-layout">
      <aside className="sidebar">
        <div className="sidebar-logo" style={{ color: "#DC2626" }}>Admin Panel</div>
        <ul className="sidebar-nav">
          <li><Link to="/admin/dashboard">📋 All Applications</Link></li>
        </ul>
        <div className="sidebar-footer">
          <button onClick={logout} style={{ background:"none", border:"none", color:"var(--color-text-secondary)", cursor:"pointer", fontSize:"0.875rem" }}>
            🚪 Logout
          </button>
        </div>
      </aside>

      <main className="main-content">
        <div style={{ marginBottom: "var(--space-lg)" }}>
          <Link to="/admin/dashboard" style={{ color: "var(--color-text-secondary)", fontSize: "0.875rem" }}>
            ← Back to Applications
          </Link>
        </div>

        {loading && <div className="spinner" />}

        {application && (
          <>
            <div className="topbar">
              <div>
                <h1 className="page-title">{m.business_name}</h1>
                <p className="page-subtitle">Application #{application.id}</p>
              </div>
              <span className={`badge badge-${application.status}`} style={{ fontSize: "0.875rem", padding: "0.4rem 1rem" }}>
                {application.status.replace("_", " ")}
              </span>
            </div>

            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "var(--space-lg)" }}>

              {/* ---- Merchant Info ---- */}
              <div className="card">
                <h3 style={{ fontWeight: 600, marginBottom: "var(--space-lg)" }}>Business Details</h3>
                {[
                  ["Business Name",   m.business_name],
                  ["Contact Person",  m.contact_person],
                  ["Email",           m.email],
                  ["Mobile",          m.mobile],
                  ["Business Type",   m.business_type.replace("_", " ")],
                  ["PAN Number",      m.pan_number],
                  ["GST Number",      m.gst_number],
                  ["Services",        m.services.replace(/,/g, ", ")],
                ].map(([label, value]) => (
                  <div key={label} style={{ display: "flex", justifyContent: "space-between", padding: "var(--space-sm) 0", borderBottom: "1px solid var(--color-border)" }}>
                    <span style={{ color: "var(--color-text-secondary)", fontSize: "0.875rem" }}>{label}</span>
                    <span style={{ fontWeight: 500, fontSize: "0.9375rem" }}>{value}</span>
                  </div>
                ))}
              </div>

              {/* ---- Admin Action Panel ---- */}
              <div className="card">
                <h3 style={{ fontWeight: 600, marginBottom: "var(--space-lg)" }}>Update Application</h3>

                <div className="form-group" style={{ marginBottom: "var(--space-md)" }}>
                  <label className="form-label">Status</label>
                  <select
                    className="form-select"
                    value={newStatus}
                    onChange={(e) => setNewStatus(e.target.value)}
                    style={{ border: "1.5px solid var(--color-border)", borderRadius: "var(--radius-md)", padding: "0.625rem var(--space-md)", width: "100%", fontFamily: "var(--font-body)" }}
                  >
                    {STATUS_OPTIONS.map((opt) => (
                      <option key={opt.value} value={opt.value}>{opt.label}</option>
                    ))}
                  </select>
                </div>

                <div className="form-group" style={{ marginBottom: "var(--space-md)" }}>
                  <label className="form-label">Remarks / Comments</label>
                  <textarea
                    rows={4}
                    value={remarks}
                    onChange={(e) => setRemarks(e.target.value)}
                    placeholder="Add admin notes or reason for rejection..."
                    style={{
                      width: "100%", padding: "0.625rem var(--space-md)",
                      border: "1.5px solid var(--color-border)", borderRadius: "var(--radius-md)",
                      fontFamily: "var(--font-body)", fontSize: "0.9375rem", resize: "vertical"
                    }}
                  />
                </div>

                {updateMsg && (
                  <div className={`alert ${updateMsg.includes("success") ? "alert-success" : "alert-error"}`}>
                    {updateMsg}
                  </div>
                )}

                <button
                  className="btn btn-primary"
                  onClick={handleUpdateStatus}
                  disabled={updating}
                  style={{ width: "100%" }}
                >
                  {updating ? "Updating..." : "Update Status"}
                </button>
              </div>
            </div>

            {/* ---- Uploaded Documents ---- */}
            <div className="card" style={{ marginTop: "var(--space-lg)" }}>
              <h3 style={{ fontWeight: 600, marginBottom: "var(--space-lg)" }}>Uploaded Documents</h3>
              {application.documents.length === 0 ? (
                <p style={{ color: "var(--color-text-secondary)" }}>No documents uploaded yet.</p>
              ) : (
                <table className="data-table">
                  <thead>
                    <tr>
                      <th>Document Type</th>
                      <th>File Name</th>
                      <th>Uploaded On</th>
                      <th>Action</th>
                    </tr>
                  </thead>
                  <tbody>
                    {application.documents.map((doc) => (
                      <tr key={doc.id}>
                        <td>{doc.doc_type.replace(/_/g, " ")}</td>
                        <td>{doc.file_name}</td>
                        <td>{new Date(doc.uploaded_at).toLocaleDateString("en-IN")}</td>
                        <td>
                          {/* Direct download link — served as static file by FastAPI */}
                          <a
                            href={`${apiBase}/${(doc.file_path || "").replace(/^\/+/, "").replace(/\\/g, "/")}`}
                            target="_blank"
                            rel="noopener noreferrer"
                            style={{ color: "var(--color-primary)", fontWeight: 500, fontSize: "0.875rem" }}
                          >
                            View / Download ↗
                          </a>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              )}
            </div>
          </>
        )}
      </main>
    </div>
  );
}

export default ApplicationDetails;
